const n="/api/owner",s={getAll:async(o,t)=>{try{const r=new URLSearchParams({ownerId:o,...t}).toString(),e=await fetch(`${n}/turf?${r}`);if(!e.ok)throw new Error("Network response was not ok");return await e.json()}catch(r){throw console.error("Error fetching turf:",r),r}},getById:async(o,t)=>{try{const r=await fetch(`${n}/turf/${t}?ownerId=${o}`);if(!r.ok)throw new Error("Network response was not ok");return await r.json()}catch(r){throw console.error("Error fetching turf details:",r),r}},create:async(o,t)=>{try{const r=await fetch(`${n}/turf`,{method:"POST",headers:{"Content-Type":"application/json"},body:JSON.stringify({...t,ownerId:o})});if(!r.ok)throw new Error("Network response was not ok");return await r.json()}catch(r){throw console.error("Error creating turf:",r),r}},update:async(o,t,r)=>{try{const e=await fetch(`${n}/turf/${t}`,{method:"PUT",headers:{"Content-Type":"application/json"},body:JSON.stringify({...r,ownerId:o})});if(!e.ok)throw new Error("Network response was not ok");return await e.json()}catch(e){throw console.error("Error updating turf:",e),e}},delete:async(o,t)=>{try{const r=await fetch(`${n}/turf/${t}?ownerId=${o}`,{method:"DELETE"});if(!r.ok)throw new Error("Network response was not ok");return await r.json()}catch(r){throw console.error("Error deleting turf:",r),r}}};export{s as t};
